select professori.cognome, studenti.cognome, studenti.nome, studenti.matricola
from studenti right join professori on id = relatore
order by professori.id;

select cdl.denominazione, max(voto)
from esami e join corsi c on c.id = e.corso join corsidilaurea cdl on cdl.id = c.corsodilaurea
group by cdl.denominazione;
